import React, { useState } from 'react';
import { PageHeader, Modal } from '../../components/UI';
import { exercisesDatabase } from '../../data/exerciseGifs-POPULATED';

const buildMuscleGroups = () => {
  const groupIcons = {
    biceps: 'bi-lightning-charge',
    triceps: 'bi-lightning',
    chest: 'bi-person-arms-up',
    back: 'bi-arrows-expand-vertical',
    shoulders: 'bi-award',
    legs: 'bi-activity',
    abs: 'bi-grid-3x3',
    calves: 'bi-arrow-up-circle'
  };

  const groupNames = {
    biceps: 'Biceps',
    triceps: 'Triceps',
    chest: 'Pectoraux',
    back: 'Dos',
    shoulders: 'Épaules',
    legs: 'Jambes',
    abs: 'Abdominaux',
    calves: 'Mollets'
  };

  const groupZones = {
    biceps: 'Bras',
    triceps: 'Bras',
    chest: 'Buste',
    back: 'Dos',
    shoulders: 'Épaules',
    legs: 'Jambes',
    abs: 'Core',
    calves: 'Jambes'
  };

  return Object.entries(exercisesDatabase).map(([key, exercises], id) => ({
    id: id + 1,
    nom: groupNames[key] || key,
    icon: groupIcons[key] || 'bi-lightning-charge',
    zone: groupZones[key] || 'Muscle',
    gif: exercises[0]?.gif || '',
    exercices: exercises.map(ex => ({
      nom: ex.frName,
      series: ex.series,
      gif: ex.gif,
      desc: ex.desc
    }))
  }));
};

const muscles = buildMuscleGroups();

function MediaViewer({ src, alt, style = {} }) {
  const [err, setErr] = useState(false);

  if (err || !src) return (
    <div style={{ width:'100%', height:'100%', display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:8, background:'var(--surface2)' }}>
      <i className="bi bi-camera-video-off" style={{ fontSize:32, color:'var(--red)', opacity:.5, filter:'drop-shadow(0 0 8px rgba(220,38,38,0.3))' }} />
      <span style={{ fontSize:11, color:'var(--text-dim)', textAlign:'center', padding:'0 10px' }}>{alt}</span>
    </div>
  );

  const isVideo = src.endsWith('.mp4');

  return isVideo ? (
    <video 
      src={src} 
      autoPlay 
      loop 
      muted 
      playsInline
      onError={() => setErr(true)} 
      style={{ width:'100%', height:'100%', objectFit:'cover', display:'block', ...style }} 
    />
  ) : (
    <img 
      src={src} 
      alt={alt} 
      onError={() => setErr(true)} 
      style={{ width:'100%', height:'100%', objectFit:'cover', display:'block', ...style }} 
    />
  );
}

export default function Musculation() {
  const [selected, setSelected] = useState(null);
  const [activeExo, setActiveExo] = useState(null);

  const openMuscle = (m) => { setSelected(m); setActiveExo(null); };
  const displayedMedia = activeExo?.gif ?? selected?.gif;

  return (
    <div style={{ paddingBottom: '40px', minHeight: '100vh', background: 'radial-gradient(circle at top right, #1a0b0b 0%, var(--bg-dark) 40%)' }}>
      <div style={{ padding: '0 28px' }}>
        <PageHeader eyebrow="Guide d'entraînement" title="Anatomie &" accent="Exercices" />
        <p style={{ fontSize:14, color:'var(--text-muted)', maxWidth:600, marginTop:'-10px', marginBottom:30, lineHeight:1.5 }}>
          Explorez les groupes musculaires pour découvrir les meilleurs mouvements. Sélectionnez un exercice pour visualiser l'exécution parfaite en vidéo.
        </p>
      </div>

      {/* Grille muscles */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(260px, 1fr))', gap:20, padding:'0 28px' }}>
        {muscles.map(m => (
          <div 
            key={m.id} 
            className="hoverable" 
            style={{ 
              overflow:'hidden', 
              padding:0, 
              background: 'rgba(255,255,255,0.02)',
              border: '1px solid rgba(255,255,255,0.05)',
              borderRadius: 16,
              cursor: 'pointer',
              transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
              boxShadow: '0 4px 20px rgba(0,0,0,0.2)',
              display: 'flex',
              flexDirection: 'column'
            }} 
            onClick={() => openMuscle(m)}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = 'translateY(-4px)';
              e.currentTarget.style.borderColor = 'rgba(220,38,38,0.3)';
              e.currentTarget.style.boxShadow = '0 12px 30px rgba(220,38,38,0.1)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.borderColor = 'rgba(255,255,255,0.05)';
              e.currentTarget.style.boxShadow = '0 4px 20px rgba(0,0,0,0.2)';
            }}
          >
            <div style={{ position: 'relative', width: '100%', height: 160, overflow:'hidden', background:'#000' }}>
              <div style={{ position: 'absolute', inset: 0, opacity: 0.8 }}>
                <MediaViewer src={m.gif} alt={m.nom} />
              </div>
              <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to top, var(--bg-dark), transparent 80%)' }} />
              <div style={{ position: 'absolute', bottom: 12, left: 16, display: 'flex', alignItems: 'center', gap: 8 }}>
                <div style={{ width: 32, height: 32, borderRadius: 8, background: 'rgba(220,38,38,0.2)', backdropFilter: 'blur(4px)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--red)', border: '1px solid rgba(220,38,38,0.3)' }}>
                  <i className={`bi ${m.icon}`} style={{ fontSize: 16 }}></i>
                </div>
                <h3 style={{ margin: 0, fontFamily: 'var(--font-heading)', fontSize: 20, fontWeight: 700, color: '#fff', textShadow: '0 2px 4px rgba(0,0,0,0.5)' }}>
                  {m.nom}
                </h3>
              </div>
            </div>

            <div style={{ padding:'16px', flex: 1, display: 'flex', flexDirection: 'column' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
                <span style={{ fontSize:11, color:'var(--text-dim)', textTransform: 'uppercase', letterSpacing: 1, fontWeight: 600 }}>{m.zone}</span>
                <span className="fz-badge" style={{ background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)' }}>{m.exercices.length} exs</span>
              </div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: 6, flex: 1 }}>
                {m.exercices.slice(0,3).map(e => (
                  <div key={e.nom} style={{ fontSize:13, color:'var(--text-muted)', display: 'flex', alignItems: 'center', gap: 8 }}>
                    <i className="bi bi-play-circle" style={{ fontSize:12, color:'var(--red)' }}></i>
                    <span style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{e.nom}</span>
                  </div>
                ))}
              </div>
              {m.exercices.length > 3 && (
                <div style={{ fontSize:11, color:'var(--text-dim)', marginTop:12, textAlign: 'center', fontStyle: 'italic' }}>
                  +{m.exercices.length - 3} autres exercices...
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Modale */}
      <Modal show={!!selected} title={selected?.nom} onClose={() => setSelected(null)} size="lg">
        {selected && (
          <div style={{ animation: 'fadeIn 0.3s ease' }}>
            <div style={{ display:'flex', gap:12, marginBottom:20, flexWrap:'wrap', alignItems:'center' }}>
              <span className="fz-badge type" style={{ background: 'rgba(220,38,38,0.1)', color: 'var(--red)', border: '1px solid rgba(220,38,38,0.2)' }}>
                <i className={`bi ${selected.icon} me-2`}></i>{selected.zone}
              </span>
              <span style={{ fontSize:13, color:'var(--text-dim)' }}>• {selected.exercices.length} exercices</span>

              {activeExo && (
                <button 
                  onClick={() => setActiveExo(null)} 
                  style={{ 
                    marginLeft:'auto', 
                    background: 'rgba(255,255,255,0.05)', 
                    border: '1px solid rgba(255,255,255,0.1)',
                    borderRadius: 20,
                    padding: '4px 12px',
                    color: '#fff',
                    fontSize: 12,
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    gap: 6,
                    transition: 'all 0.2s'
                  }}
                  onMouseEnter={(e) => e.currentTarget.style.background = 'rgba(255,255,255,0.1)'}
                  onMouseLeave={(e) => e.currentTarget.style.background = 'rgba(255,255,255,0.05)'}
                >
                  <i className="bi bi-arrow-left"></i> Retour au groupe
                </button>
              )}
            </div>

            {/* Media principal */}
            <div style={{ 
              marginBottom:24, 
              borderRadius:16, 
              border:'1px solid rgba(255,255,255,0.05)', 
              height:300, 
              overflow:'hidden', 
              background:'#050505', 
              position:'relative',
              boxShadow: 'inset 0 0 40px rgba(0,0,0,0.5)'
            }}>
              <MediaViewer src={displayedMedia} alt={activeExo?.nom ?? selected.nom} style={{ objectFit:'contain' }} />

              <div style={{
                position:'absolute', bottom:0, left:0, right:0,
                background:'linear-gradient(transparent, rgba(0,0,0,0.9) 80%)',
                padding:'40px 20px 16px',
                display:'flex', alignItems:'center', gap:12
              }}>
                <div style={{ width: 40, height: 40, borderRadius: '50%', background: 'var(--red)', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 12px rgba(220,38,38,0.4)' }}>
                  <i className="bi bi-play-fill" style={{ color:'#fff', fontSize:20, marginLeft: 2 }}></i>
                </div>
                <div>
                  <div style={{ fontFamily:'var(--font-heading)', fontSize:18, fontWeight:800, color:'#fff', lineHeight: 1.2 }}>
                    {activeExo ? activeExo.nom : selected.nom}
                  </div>
                  {activeExo && <div style={{ fontSize: 12, color: 'var(--text-dim)', marginTop: 2 }}>Visualisation de l'exercice</div>}
                </div>
              </div>
            </div>

            {/* Liste exercices */}
            <h4 style={{ fontSize: 16, fontFamily: 'var(--font-heading)', fontWeight: 600, marginBottom: 12, color: '#fff' }}>
              Exercices pour {selected.nom.toLowerCase()}
            </h4>

            <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
              {selected.exercices.map((e) => {
                const isActive = activeExo?.nom === e.nom;
                return (
                  <div
                    key={e.nom}
                    onClick={() => setActiveExo(isActive ? null : e)}
                    style={{
                      background: isActive ? 'rgba(220,38,38,0.05)' : 'var(--surface2)',
                      borderRadius:12, padding:'16px',
                      cursor:'pointer',
                      transition:'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)',
                      border: isActive ? '1px solid rgba(220,38,38,0.3)' : '1px solid rgba(255,255,255,0.03)',
                      boxShadow: isActive ? '0 4px 20px rgba(220,38,38,0.1)' : 'none',
                      position: 'relative',
                      overflow: 'hidden'
                    }}
                    onMouseEnter={(ev) => {
                      if (!isActive) {
                        ev.currentTarget.style.background = 'rgba(255,255,255,0.05)';
                        ev.currentTarget.style.transform = 'translateX(4px)';
                      }
                    }}
                    onMouseLeave={(ev) => {
                      if (!isActive) {
                        ev.currentTarget.style.background = 'var(--surface2)';
                        ev.currentTarget.style.transform = 'translateX(0)';
                      }
                    }}
                  >
                    {isActive && (
                      <div style={{ position: 'absolute', left: 0, top: 0, bottom: 0, width: 4, background: 'var(--red)', boxShadow: '0 0 10px var(--red)' }} />
                    )}

                    <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between' }}>
                      <div style={{ display:'flex', gap:16, flex: 1 }}>
                        <div style={{
                          width:36, height:36, borderRadius:10,
                          background: isActive ? 'var(--red)' : 'rgba(255,255,255,0.05)',
                          display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0,
                          transition: 'all 0.2s'
                        }}>
                          <i className={`bi bi-${isActive ? 'camera-video-fill' : 'play-fill'}`}
                            style={{ fontSize:16, color: isActive ? '#fff' : 'var(--text-muted)' }} />
                        </div>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontFamily:'var(--font-heading)', fontSize:16, fontWeight:700, color: isActive ? '#fff' : 'var(--text-bright)', marginBottom: 4 }}>
                            {e.nom}
                          </div>
                          <p style={{ fontSize:13, color:'var(--text-muted)', margin:0, lineHeight:1.5 }}>
                            {e.desc}
                          </p>
                        </div>
                      </div>
                      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 6, marginLeft: 16 }}>
                        <span className="fz-badge type" style={{ background: 'rgba(255,255,255,0.08)' }}>{e.series}</span>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
}
